#include <stdio.h>
#include <inttypes.h>
int main() {
    int T; if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        long long N, A, B;
        scanf("%lld %lld %lld", &N, &A, &B);
        long long odd = (N + 1) / 2; // episodes 1,3,5,...
        long long even = N / 2;      // episodes 2,4,6,...
        long long total = odd * B + even * A;
        printf("%lld\n", total);
    }
    return 0;
}

